{
  "name": "Win7 Portfolio & Gemini Studio",
  "description": "A Windows 7-themed portfolio featuring Aero Glass aesthetics, draggable windows, and integrated Gemini AI tools for chat and high-quality image generation."
}

export enum AppId {
  ABOUT = 'ABOUT',
  PROJECTS = 'PROJECTS',
  CONTACT = 'CONTACT',
  CHAT = 'CHAT',
  IMAGE_GEN = 'IMAGE_GEN',
}

export interface WindowState {
  id: AppId;
  title: string;
  icon: any; // Lucide icon component
  isOpen: boolean;
  isMinimized: boolean;
  isMaximized: boolean;
  zIndex: number;
  position: { x: number; y: number };
  size: { width: number; height: number };
}

export enum ImageResolution {
  ONE_K = '1K',
  TWO_K = '2K',
  FOUR_K = '4K',
}

export interface ChatMessage {
  role: 'user' | 'model';
  text: string;
  timestamp: Date;
}

import { GoogleGenAI, GenerateContentResponse } from "@google/genai";
import { ImageResolution, ChatMessage } from "../types";

// Helper to check for API Key selection (mocked for environment if needed, but using window object as per prompt)
export const checkApiKeySelection = async (): Promise<boolean> => {
  if (typeof (window as any).aistudio?.hasSelectedApiKey === 'function') {
    return await (window as any).aistudio.hasSelectedApiKey();
  }
  return true; // Fallback if not in the specific environment, assuming env var exists
};

export const promptApiKeySelection = async (): Promise<void> => {
  if (typeof (window as any).aistudio?.openSelectKey === 'function') {
    await (window as any).aistudio.openSelectKey();
  }
};

export const generateImage = async (prompt: string, resolution: ImageResolution): Promise<string | null> => {
  try {
    // Determine model based on resolution request as per prompt guidelines
    // High quality (2K/4K) -> gemini-3-pro-image-preview
    // 1K can be either, but prompt says "Upgrade to ... if user requests high-quality".
    // Prompt feature request says "generate images ... using model gemini-3-pro-image-preview".
    // So we will use pro-image-preview for all sizes in this specific "Nano Banana Pro" feature.

    // Create new instance to ensure fresh key if just selected
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-image-preview',
      contents: {
        parts: [{ text: prompt }],
      },
      config: {
        imageConfig: {
          imageSize: resolution,
          aspectRatio: "1:1" // Default square
        }
      },
    });

    // Extract image
    if (response.candidates && response.candidates[0].content.parts) {
      for (const part of response.candidates[0].content.parts) {
        if (part.inlineData) {
          return `data:image/png;base64,${part.inlineData.data}`;
        }
      }
    }
    return null;

  } catch (error) {
    console.error("Image generation failed:", error);
    throw error;
  }
};

export const sendChatMessage = async (history: ChatMessage[], newMessage: string): Promise<string> => {
  try {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

    // Construct chat history for context if needed, but simple generateContent with history is often easier managed via ChatSession.
    // Here we'll just use a fresh chat session for simplicity or stateless single turn if we don't want to manage full history object mapping.
    // However, for a chat bot, history is good.

    const chat = ai.chats.create({
      model: 'gemini-3-pro-preview',
      history: history.map(h => ({
        role: h.role,
        parts: [{ text: h.text }]
      }))
    });

    const result: GenerateContentResponse = await chat.sendMessage({ message: newMessage });
    return result.text || "I couldn't generate a text response.";
  } catch (error) {
    console.error("Chat failed:", error);
    return "Sorry, I encountered an error processing your request.";
  }
};

import React, { useState, useEffect, useRef } from 'react';
import { X, Minus, Square, Maximize2 } from 'lucide-react';
import { WindowState, AppId } from '../../types';

interface WindowProps {
  windowState: WindowState;
  onClose: (id: AppId) => void;
  onMinimize: (id: AppId) => void;
  onMaximize: (id: AppId) => void;
  onFocus: (id: AppId) => void;
  onMove: (id: AppId, x: number, y: number) => void;
  children: React.ReactNode;
}

export const Window: React.FC<WindowProps> = ({
  windowState,
  onClose,
  onMinimize,
  onMaximize,
  onFocus,
  onMove,
  children,
}) => {
  const [isDragging, setIsDragging] = useState(false);
  const [dragOffset, setDragOffset] = useState({ x: 0, y: 0 });
  const windowRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const handleMouseMove = (e: MouseEvent) => {
      if (isDragging) {
        onMove(windowState.id, e.clientX - dragOffset.x, e.clientY - dragOffset.y);
      }
    };

    const handleMouseUp = () => {
      setIsDragging(false);
    };

    if (isDragging) {
      document.addEventListener('mousemove', handleMouseMove);
      document.addEventListener('mouseup', handleMouseUp);
    }

    return () => {
      document.removeEventListener('mousemove', handleMouseMove);
      document.removeEventListener('mouseup', handleMouseUp);
    };
  }, [isDragging, dragOffset, onMove, windowState.id]);

  const handleMouseDown = (e: React.MouseEvent) => {
    // Only drag if clicking the header
    if ((e.target as HTMLElement).closest('.window-controls')) return;

    onFocus(windowState.id);
    setIsDragging(true);
    setDragOffset({
      x: e.clientX - windowState.position.x,
      y: e.clientY - windowState.position.y
    });
  };

  if (!windowState.isOpen || windowState.isMinimized) return null;

  return (
    <div
      ref={windowRef}
      className={`absolute flex flex-col glass-panel window-shadow rounded-lg overflow-hidden transition-opacity duration-200 ${
        isDragging ? 'cursor-grabbing' : ''
      }`}
      style={{
        left: windowState.position.x,
        top: windowState.position.y,
        width: windowState.size.width,
        height: windowState.size.height,
        zIndex: windowState.zIndex,
      }}
      onMouseDown={() => onFocus(windowState.id)}
    >
      {/* Window Header (Aero Titlebar) */}
      <div
        className="h-8 flex items-center justify-between px-2 cursor-default select-none bg-gradient-to-b from-white/50 to-transparent border-b border-white/20"
        onMouseDown={handleMouseDown}
      >
        <div className="flex items-center gap-2 px-1 text-slate-800 shadow-black drop-shadow-sm">
          <windowState.icon size={16} className="text-slate-900 opacity-80" />
          <span className="text-xs font-semibold tracking-wide text-slate-900/90" style={{ textShadow: '0 0 5px rgba(255,255,255,0.8)' }}>
            {windowState.title}
          </span>
        </div>

        <div className="flex items-center window-controls gap-1">
          <button
            onClick={(e) => { e.stopPropagation(); onMinimize(windowState.id); }}
            className="w-6 h-5 flex items-center justify-center hover:bg-white/40 rounded-sm border border-transparent hover:border-white/30 transition-colors"
          >
            <Minus size={12} className="text-slate-800" />
          </button>
          <button
            onClick={(e) => { e.stopPropagation(); onMaximize(windowState.id); }}
            className="w-6 h-5 flex items-center justify-center hover:bg-white/40 rounded-sm border border-transparent hover:border-white/30 transition-colors"
          >
             {windowState.isMaximized ? <Square size={10} className="text-slate-800" /> : <Maximize2 size={10} className="text-slate-800" />}
          </button>
          <button
            onClick={(e) => { e.stopPropagation(); onClose(windowState.id); }}
            className="w-10 h-5 flex items-center justify-center hover:bg-[#e81123] bg-transparent hover:text-white rounded-sm border border-transparent transition-colors group"
          >
            <X size={14} className="text-slate-800 group-hover:text-white" />
          </button>
        </div>
      </div>

      {/* Window Content */}
      <div className="flex-1 bg-white/80 overflow-hidden relative flex flex-col">
        {children}
      </div>
    </div>
  );
};

