import React, { useState, useEffect } from 'react';
import { Taskbar } from './components/ui/Taskbar';
import { StartMenu } from './components/ui/StartMenu';
import { Window } from './components/ui/Window';
import { AboutApp } from './components/apps/AboutApp';
import { ProjectsApp } from './components/apps/ProjectsApp';
import { GeminiImageApp } from './components/apps/GeminiImageApp';
import { ChatApp } from './components/apps/ChatApp';
import { AppId, WindowState } from './types';
import { User, Briefcase, Mail, MessageSquare, Image as ImageIcon } from 'lucide-react';

const INITIAL_WINDOWS: WindowState[] = [
  {
    id: AppId.ABOUT,
    title: 'About Me',
    icon: User,
    isOpen: true,
    isMinimized: false,
    isMaximized: false,
    zIndex: 1,
    position: { x: 50, y: 50 },
    size: { width: 600, height: 450 },
  },
  {
    id: AppId.PROJECTS,
    title: 'My Projects',
    icon: Briefcase,
    isOpen: false,
    isMinimized: false,
    isMaximized: false,
    zIndex: 2,
    position: { x: 100, y: 80 },
    size: { width: 700, height: 500 },
  },
  {
    id: AppId.CONTACT,
    title: 'Contact',
    icon: Mail,
    isOpen: false,
    isMinimized: false,
    isMaximized: false,
    zIndex: 3,
    position: { x: 150, y: 110 },
    size: { width: 400, height: 300 },
  },
  {
    id: AppId.CHAT,
    title: 'Gemini Chat',
    icon: MessageSquare,
    isOpen: false,
    isMinimized: false,
    isMaximized: false,
    zIndex: 4,
    position: { x: 400, y: 100 },
    size: { width: 400, height: 500 },
  },
  {
    id: AppId.IMAGE_GEN,
    title: 'Nano Banana Studio',
    icon: ImageIcon,
    isOpen: false,
    isMinimized: false,
    isMaximized: false,
    zIndex: 5,
    position: { x: 450, y: 150 },
    size: { width: 600, height: 650 },
  },
];

const App: React.FC = () => {
  const [windows, setWindows] = useState<WindowState[]>(INITIAL_WINDOWS);
  const [activeWindowId, setActiveWindowId] = useState<AppId | null>(AppId.ABOUT);
  const [isStartOpen, setIsStartOpen] = useState(false);
  const [maxZIndex, setMaxZIndex] = useState(5);

  const handleFocus = (id: AppId) => {
    setActiveWindowId(id);
    setWindows(prev => prev.map(w => 
      w.id === id ? { ...w, zIndex: maxZIndex + 1, isMinimized: false } : w
    ));
    setMaxZIndex(z => z + 1);
  };

  const handleOpenApp = (id: AppId) => {
    const target = windows.find(w => w.id === id);
    if (!target) return;

    if (target.isOpen) {
        if (target.isMinimized) {
            handleFocus(id);
        } else {
            handleFocus(id);
        }
    } else {
        setWindows(prev => prev.map(w => 
            w.id === id ? { ...w, isOpen: true, zIndex: maxZIndex + 1 } : w
        ));
        setMaxZIndex(z => z + 1);
        setActiveWindowId(id);
    }
  };

  const handleClose = (id: AppId) => {
    setWindows(prev => prev.map(w => w.id === id ? { ...w, isOpen: false, isMinimized: false } : w));
    if (activeWindowId === id) setActiveWindowId(null);
  };

  const handleMinimize = (id: AppId) => {
    setWindows(prev => prev.map(w => w.id === id ? { ...w, isMinimized: true } : w));
    if (activeWindowId === id) setActiveWindowId(null);
  };

  const handleMaximize = (id: AppId) => {
     setWindows(prev => prev.map(w => {
         if (w.id !== id) return w;
         if (w.isMaximized) {
             // Restore
             return { ...w, isMaximized: false, position: { x: 50 + (Math.random() * 50), y: 50 + (Math.random() * 50) }, size: { width: 600, height: 500 } };
         } else {
             // Maximize (simulate by setting to window inner sizes minus taskbar)
             return { ...w, isMaximized: true, position: { x: 0, y: 0 }, size: { width: window.innerWidth, height: window.innerHeight - 40 } };
         }
     }));
     handleFocus(id);
  };

  const handleMove = (id: AppId, x: number, y: number) => {
    setWindows(prev => prev.map(w => 
      w.id === id && !w.isMaximized ? { ...w, position: { x, y } } : w
    ));
  };

  const handleTaskbarClick = (id: AppId) => {
      const w = windows.find(win => win.id === id);
      if (w?.isMinimized || activeWindowId !== id) {
          handleFocus(id);
      } else {
          handleMinimize(id);
      }
      setIsStartOpen(false);
  };

  return (
    <div 
      className="h-screen w-screen overflow-hidden relative"
      style={{
        background: 'linear-gradient(135deg, #1e5799 0%, #2989d8 50%, #207cca 51%, #7db9e8 100%)' // Classic Blue Gradient approximation
      }}
      onClick={() => setIsStartOpen(false)}
    >
      {/* Desktop Icons */}
      <div className="absolute top-4 left-4 grid grid-flow-row gap-6">
        {windows.map(app => (
            <button 
                key={app.id}
                onDoubleClick={() => handleOpenApp(app.id)}
                className="flex flex-col items-center gap-1 w-20 group text-center cursor-default hover:bg-white/10 rounded border border-transparent hover:border-white/20 p-2 transition-colors"
                onClick={(e) => e.stopPropagation()}
            >
                <div className="drop-shadow-2xl filter shadow-black">
                    <app.icon size={42} className="text-white drop-shadow-[0_2px_4px_rgba(0,0,0,0.6)]" strokeWidth={1.5} />
                </div>
                <span className="text-white text-xs drop-shadow-[0_1px_2px_rgba(0,0,0,0.8)] font-medium leading-tight group-hover:line-clamp-none line-clamp-2">
                    {app.title}
                </span>
            </button>
        ))}
      </div>

      {/* Windows Layer */}
      {windows.map(window => (
        <Window
          key={window.id}
          windowState={window}
          onClose={handleClose}
          onMinimize={handleMinimize}
          onMaximize={handleMaximize}
          onFocus={handleFocus}
          onMove={handleMove}
        >
          {window.id === AppId.ABOUT && <AboutApp />}
          {window.id === AppId.PROJECTS && <ProjectsApp />}
          {window.id === AppId.CONTACT && (
              <div className="p-8 text-center bg-white h-full flex flex-col items-center justify-center text-slate-700">
                  <Mail size={48} className="text-blue-500 mb-4" />
                  <h2 className="text-2xl font-bold mb-2">Get in Touch</h2>
                  <p className="mb-6 max-w-xs">I'm currently available for freelance work and full-time opportunities.</p>
                  <a href="mailto:contact@johndoe.dev" className="px-6 py-2 bg-blue-600 hover:bg-blue-700 text-white rounded shadow-sm">
                      Send Email
                  </a>
              </div>
          )}
          {window.id === AppId.CHAT && <ChatApp />}
          {window.id === AppId.IMAGE_GEN && <GeminiImageApp />}
        </Window>
      ))}

      {/* System UI */}
      <StartMenu 
        isOpen={isStartOpen} 
        apps={windows} 
        onOpenApp={handleOpenApp} 
        onClose={() => setIsStartOpen(false)} 
      />

      <Taskbar 
        windows={windows} 
        activeWindowId={activeWindowId} 
        onAppClick={handleTaskbarClick} 
        onStartClick={() => setIsStartOpen(!isStartOpen)}
        isStartOpen={isStartOpen}
      />
    </div>
  );
};

export default App;

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

