import { ChatApp } from './components/apps/ChatApp';
import { AppId, WindowState } from './types';
import { User, Briefcase, Mail, MessageSquare, Github } from 'lucide-react';

const INITIAL_WINDOWS: WindowState[] = [
  {
    id: AppId.ABOUT,
    title: 'About Me',
    icon: User,
    isOpen: true,
    isMinimized: false,
    isMaximized: false,
    zIndex: 1,
    position: { x: 50, y: 50 },
    size: { width: 600, height: 450 },
  },
  {
    id: AppId.PROJECTS,
    title: 'My Projects',
    icon: Briefcase,
    isOpen: false,
    isMinimized: false,
    isMaximized: false,
    zIndex: 2,
    position: { x: 100, y: 80 },
    size: { width: 750, height: 500 },
  },
  {
    id: AppId.TERMINAL,
    title: 'Keshav AI Terminal',
    icon: MessageSquare,
    isOpen: false,
    isMinimized: false,
    isMaximized: false,
    zIndex: 3,
    position: { x: 150, y: 110 },
    size: { width: 500, height: 600 },
  },
  {
    id: AppId.CONTACT,
    title: 'Contact',
    icon: Mail,
    isOpen: false,
    isMinimized: false,
    isMaximized: false,
    zIndex: 4,
    position: { x: 200, y: 140 },
    size: { width: 400, height: 300 },
  },
];

const App: React.FC = () => {
  const [windows, setWindows] = useState<WindowState[]>(INITIAL_WINDOWS);
  const [activeWindowId, setActiveWindowId] = useState<AppId | null>(AppId.ABOUT);
  const [isStartOpen, setIsStartOpen] = useState(false);
  const [maxZIndex, setMaxZIndex] = useState(5);

  const handleFocus = (id: AppId) => {
    setActiveWindowId(id);
    setWindows(prev => prev.map(w => 
      w.id === id ? { ...w, zIndex: maxZIndex + 1, isMinimized: false } : w
    ));
    setMaxZIndex(z => z + 1);
  };

  const handleOpenApp = (id: AppId) => {
    // Handle external apps (Links)
    if (id === AppId.GITHUB) {
        window.open('https://github.com/Keshav-gehlot', '_blank');
        return;
    }

    const target = windows.find(w => w.id === id);
    if (!target) return;

    if (target.isOpen) {
        handleFocus(id);
    } else {
        setWindows(prev => prev.map(w => 
            w.id === id ? { ...w, isOpen: true, zIndex: maxZIndex + 1, isMinimized: false } : w
        ));
        setMaxZIndex(z => z + 1);
        setActiveWindowId(id);
    }
  };

  const handleClose = (id: AppId) => {
    setWindows(prev => prev.map(w => w.id === id ? { ...w, isOpen: false, isMinimized: false } : w));
    if (activeWindowId === id) setActiveWindowId(null);
  };

  const handleMinimize = (id: AppId) => {
    setWindows(prev => prev.map(w => w.id === id ? { ...w, isMinimized: true } : w));
    if (activeWindowId === id) setActiveWindowId(null);
  };

  const handleMaximize = (id: AppId) => {
     setWindows(prev => prev.map(w => {
         if (w.id !== id) return w;
         if (w.isMaximized) {
             // Restore
             return { 
                ...w, 
                isMaximized: false, 
                position: { x: 50 + (Math.random() * 50), y: 50 + (Math.random() * 50) }, 
                size: w.id === AppId.PROJECTS ? { width: 750, height: 500 } : { width: 600, height: 450 } 
             };
         } else {
             // Maximize (simulate by setting to window inner sizes minus taskbar)
             return { ...w, isMaximized: true, position: { x: 0, y: 0 }, size: { width: window.innerWidth, height: window.innerHeight - 40 } };
         }
     }));
     handleFocus(id);
  };

  const handleMove = (id: AppId, x: number, y: number) => {
    setWindows(prev => prev.map(w => 
      w.id === id && !w.isMaximized ? { ...w, position: { x, y } } : w
    ));
  };

  const handleTaskbarClick = (id: AppId) => {
      const w = windows.find(win => win.id === id);
      if (w?.isMinimized || activeWindowId !== id) {
          handleFocus(id);
      } else {
          handleMinimize(id);
      }
      setIsStartOpen(false);
  };

  // Extra Desktop Icons mapping
  const desktopIcons = [
      { id: AppId.ABOUT, label: 'About Me', icon: User },
      { id: AppId.PROJECTS, label: 'Projects', icon: Briefcase },
      { id: AppId.TERMINAL, label: 'Terminal', icon: MessageSquare },
      { id: AppId.GITHUB, label: 'GitHub', icon: Github },
  ];

  return (
    <div 
      className="h-screen w-screen overflow-hidden relative"
      style={{
        background: 'url("https://images.unsplash.com/photo-1579546929518-9e396f3cc809?ixlib=rb-4.0.3&auto=format&fit=crop&w=1920&q=80") center/cover no-repeat'
      }}
      onClick={() => setIsStartOpen(false)}
    >
      {/* Desktop Icons */}
      <div className="absolute top-4 left-4 flex flex-col gap-6 items-start z-0">
        {desktopIcons.map(icon => (
            <button 
                key={icon.id}
                onDoubleClick={(e) => { e.stopPropagation(); handleOpenApp(icon.id); }}
                className="flex flex-col items-center gap-1 w-[80px] group text-center cursor-default hover:bg-white/10 rounded border border-transparent hover:border-white/20 p-2 transition-colors focus:bg-white/20 focus:border-white/30 active:bg-white/20"
                onClick={(e) => e.stopPropagation()}
            >
                <div className="drop-shadow-2xl filter shadow-black transition-transform group-hover:scale-105 group-active:scale-95">
                    <icon.icon size={42} className="text-white drop-shadow-[0_2px_4px_rgba(0,0,0,0.6)]" strokeWidth={1.5} />
                </div>
                <span className="text-white text-xs drop-shadow-[0_1px_2px_rgba(0,0,0,1)] font-medium leading-tight line-clamp-2 shadow-black text-shadow-sm" style={{ textShadow: '0 0 4px rgba(0,0,0,0.8)' }}>
                    {icon.label}
                </span>
            </button>
        ))}
      </div>

      {/* Windows Layer */}
      {windows.map(window => (
        <Window
          key={window.id}
          windowState={window}
          onClose={handleClose}
          onMinimize={handleMinimize}
          onMaximize={handleMaximize}
          onFocus={handleFocus}
          onMove={handleMove}
        >
          {window.id === AppId.ABOUT && <AboutApp />}
          {window.id === AppId.PROJECTS && <ProjectsApp />}
          {window.id === AppId.TERMINAL && <ChatApp />}
          {window.id === AppId.CONTACT && (
              <div className="p-8 text-center bg-[#f0f2f5] h-full flex flex-col items-center justify-center text-slate-700 select-text">
                  <div className="w-20 h-20 bg-white rounded-full flex items-center justify-center shadow-md mb-6">
                      <Mail size={40} className="text-blue-500" />
                  </div>
                  <h2 className="text-2xl font-bold mb-2 text-[#1e395b]">Get in Touch</h2>
                  <p className="mb-6 max-w-xs text-slate-600 leading-relaxed">
                      I'm currently open to cybersecurity roles and freelance projects.
                  </p>
                  <a 
                    href="mailto:gehlotkeshav.kg@gmail.com" 
                    className="px-6 py-2.5 bg-gradient-to-b from-blue-500 to-blue-600 hover:from-blue-400 hover:to-blue-500 text-white rounded shadow-md border border-blue-700 font-medium active:translate-y-px transition-all"
                  >
                      Email Me
                  </a>
                  <p className="mt-8 text-xs text-slate-500">gehlotkeshav.kg@gmail.com</p>
              </div>
          )}
        </Window>
      ))}

      {/* System UI */}
      <StartMenu 
        isOpen={isStartOpen} 
        onOpenApp={handleOpenApp} 
        onClose={() => setIsStartOpen(false)} 
      />

      <Taskbar 
        windows={windows} 
        activeWindowId={activeWindowId} 
        onAppClick={handleTaskbarClick} 
        onStartClick={() => setIsStartOpen(!isStartOpen)}
        isStartOpen={isStartOpen}
      />
    </div>
  );
};

