import { Window } from './components/ui/Window';
import { LiveBackground } from './components/ui/LiveBackground';
import { LoginScreen } from './components/ui/LoginScreen';
import { ContextMenu } from './components/ui/ContextMenu';
import { AboutApp } from './components/apps/AboutApp';
import { ProjectsApp } from './components/apps/ProjectsApp';
import { ChatApp } from './components/apps/ChatApp';
import { ContactApp } from './components/apps/ContactApp';
import { GeminiImageApp } from './components/apps/GeminiImageApp';
import { AppId, WindowState } from './types';
import { User, Briefcase, Mail, MessageSquare, Github, Image as ImageIcon } from 'lucide-react';
import { soundService } from './services/soundService';

const INITIAL_WINDOWS: WindowState[] = [
  {
    id: AppId.ABOUT,
    title: 'About Me',
    icon: User,
    isOpen: true,
    isMinimized: false,
    isMaximized: false,
    zIndex: 1,
    position: { x: 50, y: 50 },
    size: { width: 600, height: 450 },
  },
  {
    id: AppId.PROJECTS,
    title: 'My Projects',
    icon: Briefcase,
    isOpen: false,
    isMinimized: false,
    isMaximized: false,
    zIndex: 2,
    position: { x: 100, y: 80 },
    size: { width: 750, height: 500 },
  },
  {
    id: AppId.CHAT,
    title: 'Keshav AI Chat',
    icon: MessageSquare,
    isOpen: false,
    isMinimized: false,
    isMaximized: false,
    zIndex: 3,
    position: { x: 150, y: 110 },
    size: { width: 500, height: 600 },
  },
  {
    id: AppId.CONTACT,
    title: 'Contact',
    icon: Mail,
    isOpen: false,
    isMinimized: false,
    isMaximized: false,
    zIndex: 4,
    position: { x: 200, y: 140 },
    size: { width: 650, height: 450 },
  },
  {
    id: AppId.AI_IMAGE_GEN,
    title: 'AI Image Generator',
    icon: ImageIcon,
    isOpen: false,
    isMinimized: false,
    isMaximized: false,
    zIndex: 5,
    position: { x: 250, y: 170 },
    size: { width: 700, height: 550 },
  },
];

const App: React.FC = () => {
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [windows, setWindows] = useState<WindowState[]>(INITIAL_WINDOWS);
  const [activeWindowId, setActiveWindowId] = useState<AppId | null>(AppId.ABOUT);
  const [isStartOpen, setIsStartOpen] = useState(false);
  const [maxZIndex, setMaxZIndex] = useState(5);

  // New States
  const [contextMenu, setContextMenu] = useState<{ visible: boolean; x: number; y: number } | null>(null);
  const [isShuttingDown, setIsShuttingDown] = useState(false);
  const [bsod, setBsod] = useState(false);
  const [keySequence, setKeySequence] = useState<string[]>([]);

  // BSOD Easter Egg Listener
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      const key = e.key.toLowerCase();
      setKeySequence(prev => {
        const newSeq = [...prev, key].slice(-4);
        if (newSeq.join('') === 'bsod') {
          setBsod(true);
        }
        return newSeq;
      });
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, []);

  const handleLogin = () => {
    soundService.play('startup');
    setIsLoggedIn(true);
  };

  const handleFocus = (id: AppId) => {
    setActiveWindowId(id);
    setWindows(prev => prev.map(w => 
      w.id === id ? { ...w, zIndex: maxZIndex + 1, isMinimized: false } : w
    ));
    setMaxZIndex(z => z + 1);
  };

  const handleOpenApp = (id: AppId) => {
    if (id === AppId.GITHUB) {
        soundService.play('click');
        window.open('https://github.com/Keshav-gehlot', '_blank');
        return;
    }

    const target = windows.find(w => w.id === id);
    if (!target) return;

    if (target.isOpen) {
        handleFocus(id);
    } else {
        soundService.play('open');
        setWindows(prev => prev.map(w => 
            w.id === id ? { ...w, isOpen: true, zIndex: maxZIndex + 1, isMinimized: false } : w
        ));
        setMaxZIndex(z => z + 1);
        setActiveWindowId(id);
    }
  };

  const handleClose = (id: AppId) => {
    soundService.play('close');
    setWindows(prev => prev.map(w => w.id === id ? { ...w, isOpen: false, isMinimized: false } : w));
    if (activeWindowId === id) setActiveWindowId(null);
  };

  const handleMinimize = (id: AppId) => {
    soundService.play('minimize');
    setWindows(prev => prev.map(w => w.id === id ? { ...w, isMinimized: true } : w));
    if (activeWindowId === id) setActiveWindowId(null);
  };

  const handleMaximize = (id: AppId) => {
     setWindows(prev => prev.map(w => {
         if (w.id !== id) return w;
         if (w.isMaximized) {
             soundService.play('minimize');
             return { 
                ...w, 
                isMaximized: false, 
                position: { x: 50 + (Math.random() * 50), y: 50 + (Math.random() * 50) }, 
                size: w.id === AppId.PROJECTS ? { width: 750, height: 500 } : { width: 600, height: 450 } 
             };
         } else {
             soundService.play('open');
             return { ...w, isMaximized: true, position: { x: 0, y: 0 }, size: { width: window.innerWidth, height: window.innerHeight - 40 } };
         }
     }));
     handleFocus(id);
  };

  const handleMove = (id: AppId, x: number, y: number) => {
    setWindows(prev => prev.map(w => 
      w.id === id && !w.isMaximized ? { ...w, position: { x, y } } : w
    ));
  };

  const handleResize = (id: AppId, width: number, height: number, x: number, y: number) => {
      setWindows(prev => prev.map(w => 
          w.id === id ? { ...w, size: { width, height }, position: { x, y } } : w
      ));
  };

  const handleTaskbarClick = (id: AppId) => {
      const w = windows.find(win => win.id === id);
      soundService.play('click');
      if (w?.isMinimized || activeWindowId !== id) {
          handleFocus(id);
      } else {
          handleMinimize(id);
      }
      setIsStartOpen(false);
  };

  const handleShowDesktop = () => {
    const anyOpen = windows.some(w => w.isOpen && !w.isMinimized);
    if (anyOpen) {
        soundService.play('minimize');
        setWindows(prev => prev.map(w => ({ ...w, isMinimized: true })));
        setActiveWindowId(null);
    } else {
        // Restore logic could be implemented here to toggle back
    }
  };

  const handleContextMenu = (e: React.MouseEvent) => {
    e.preventDefault();
    setContextMenu({ visible: true, x: e.clientX, y: e.clientY });
  };

  const handleShutdown = () => {
    setIsShuttingDown(true);
    // Transition to login screen after delay instead of reload
    setTimeout(() => {
        setIsShuttingDown(false);
        setIsLoggedIn(false);
        // Reset state
        setWindows(INITIAL_WINDOWS);
        setActiveWindowId(AppId.ABOUT);
        setIsStartOpen(false);
    }, 4000);
  };

  // Extra Desktop Icons mapping
  const desktopIcons = [
      { id: AppId.ABOUT, label: 'About Me', icon: User },
      { id: AppId.PROJECTS, label: 'Projects', icon: Briefcase },
      { id: AppId.CHAT, label: 'Chat', icon: MessageSquare },
      { id: AppId.AI_IMAGE_GEN, label: 'AI Image Gen', icon: ImageIcon },
      { id: AppId.CONTACT, label: 'Contact Me', icon: Mail },
      { id: AppId.GITHUB, label: 'GitHub', icon: Github },
  ];

  if (bsod) {
      return (
          <div className="fixed inset-0 bg-[#000082] text-white font-[ 'Lucida Console', monospace] p-8 z-[99999] cursor-none" onClick={() => setBsod(false)}>
              <div className="max-w-4xl">
                <p className="mb-8">A problem has been detected and Windows has been shut down to prevent damage to your computer.</p>
                <p className="mb-8">DRIVER_IRQL_NOT_LESS_OR_EQUAL</p>
                <p className="mb-8">If this is the first time you've seen this Stop error screen, restart your computer. If this screen appears again, follow these steps:</p>
                <p className="mb-8">Check to make sure any new hardware or software is properly installed. If this is a new installation, ask your hardware or software manufacturer for any Windows updates you might need.</p>
                <p className="mb-8">Technical information:</p>
                <p className="mb-8">*** STOP: 0x000000D1 (0x0000000C, 0x00000002, 0x00000000, 0xF86B5A89)</p>
                <p className="mb-8">***  gv3.sys - Address F86B5A89 base at F86B5000, DateStamp 3dd9919eb</p>
                <p>Beginning dump of physical memory</p>
                <p>Physical memory dump complete.</p>
                <p>Contact your system administrator or technical support group for further assistance.</p>
              </div>
          </div>
      );
  }

  if (isShuttingDown) {
      return (
          <div className="fixed inset-0 z-[9999] cursor-wait select-none font-[Segoe UI,sans-serif] overflow-hidden">
               {/* Background with blur to mimic Windows 7 overlay */}
               <div className="absolute inset-0 bg-black"></div>
               <div 
                  className="absolute inset-0 bg-cover bg-center opacity-40 blur-sm"
                  style={{ backgroundImage: 'url("https://images.unsplash.com/photo-1614850523459-c2f4c699c52e?ixlib=rb-4.0.3&auto=format&fit=crop&w=1920&q=80")' }}
               ></div>

               <div className="relative z-10 h-full w-full flex flex-col items-center justify-center animate-in fade-in duration-1000">
                   <div className="flex flex-col items-center gap-6">
                       <div className="w-12 h-12 rounded-full border-4 border-white/20 border-t-white/90 border-r-white/90 animate-spin shadow-[0_0_15px_rgba(255,255,255,0.3)]"></div>
                       <div className="text-center space-y-1">
                            <h2 className="text-white text-2xl font-light tracking-wide drop-shadow-lg">Shutting down...</h2>
                            <p className="text-blue-100/80 text-base font-light tracking-wide mt-2">Thank you for visiting.</p>
                       </div>
                   </div>
               </div>
          </div>
      );
  }

  if (!isLoggedIn) {
      return <LoginScreen onLogin={handleLogin} />;
  }

  return (
    <div 
      className="h-screen w-screen overflow-hidden relative select-none animate-in fade-in duration-700"
      onClick={() => {
          setIsStartOpen(false);
          setContextMenu(null);
      }}
      onContextMenu={handleContextMenu}
    >
      {/* Background Layer - Static Wallpaper */}
      <div 
        className="absolute inset-0 z-[-2]"
        style={{
            background: 'url("https://images.unsplash.com/photo-1614850523459-c2f4c699c52e?ixlib=rb-4.0.3&auto=format&fit=crop&w=1920&q=80") center/cover no-repeat'
        }}
      />

      {/* Interactive Layer - Particles */}
      <LiveBackground />

      {/* Desktop Icons */}
      <div className="absolute top-4 left-4 flex flex-col gap-6 items-start z-0">
        {desktopIcons.map(icon => (
            <button 
                key={icon.id}
                onDoubleClick={(e) => { e.stopPropagation(); handleOpenApp(icon.id); }}
                className="flex flex-col items-center gap-1 w-[80px] group text-center cursor-default hover:bg-white/10 rounded border border-transparent hover:border-white/20 p-2 transition-colors focus:bg-white/20 focus:border-white/30 active:bg-white/20"
                onClick={(e) => { e.stopPropagation(); soundService.play('click'); }}
            >
                <div className="drop-shadow-2xl filter shadow-black transition-transform group-hover:scale-105 group-active:scale-95">
                    <icon.icon size={42} className="text-white drop-shadow-[0_2px_4px_rgba(0,0,0,0.6)]" strokeWidth={1.5} />
                </div>
                <span className="text-white text-xs drop-shadow-[0_1px_2px_rgba(0,0,0,1)] font-medium leading-tight line-clamp-2 shadow-black text-shadow-sm" style={{ textShadow: '0 0 4px rgba(0,0,0,0.8)' }}>
                    {icon.label}
                </span>
            </button>
        ))}
      </div>

      {/* Windows Layer */}
      {windows.map(window => (
        <Window
          key={window.id}
          windowState={window}
          onClose={handleClose}
          onMinimize={handleMinimize}
          onMaximize={handleMaximize}
          onFocus={handleFocus}
          onMove={handleMove}
          onResize={handleResize}
        >
          {window.id === AppId.ABOUT && <AboutApp />}
          {window.id === AppId.PROJECTS && <ProjectsApp />}
          {window.id === AppId.CHAT && <ChatApp />}
          {window.id === AppId.CONTACT && <ContactApp />}
          {window.id === AppId.AI_IMAGE_GEN && <GeminiImageApp />}
        </Window>
      ))}

      {/* Context Menu */}
      {contextMenu && (
          <ContextMenu 
            x={contextMenu.x} 
            y={contextMenu.y} 
            onClose={() => setContextMenu(null)}
            onRefresh={() => {
                // Flash effect for refresh
                const bg = document.createElement('div');
                bg.className = "absolute inset-0 bg-white/20 z-50 pointer-events-none";
                document.body.appendChild(bg);
                setTimeout(() => document.body.removeChild(bg), 50);
            }} 
          />
      )}

      {/* System UI */}
      <StartMenu 
        isOpen={isStartOpen} 
        onOpenApp={handleOpenApp} 
        onClose={() => setIsStartOpen(false)} 
        onShutdown={handleShutdown}
      />

      <Taskbar 
        windows={windows} 
        activeWindowId={activeWindowId} 
        onAppClick={handleTaskbarClick} 
        onStartClick={() => { soundService.play('click'); setIsStartOpen(!isStartOpen); }}
        isStartOpen={isStartOpen}
        onShowDesktop={handleShowDesktop}
      />
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { X, Minus, Square, Maximize2 } from 'lucide-react';
import { WindowState, AppId } from '../../types';

interface WindowProps {
  windowState: WindowState;
  onClose: (id: AppId) => void;
  onMinimize: (id: AppId) => void;
  onMaximize: (id: AppId) => void;
  onFocus: (id: AppId) => void;
  onMove: (id: AppId, x: number, y: number) => void;
  onResize: (id: AppId, width: number, height: number, x: number, y: number) => void;
  children: React.ReactNode;
}

export const Window: React.FC<WindowProps> = ({
  windowState,
  onClose,
  onMinimize,
  onMaximize,
  onFocus,
  onMove,
  onResize,
  children,
}) => {
  const [isDragging, setIsDragging] = useState(false);
  const [dragOffset, setDragOffset] = useState({ x: 0, y: 0 });

  const [isResizing, setIsResizing] = useState(false);
  const [resizeDir, setResizeDir] = useState<string | null>(null);
  const [startResize, setStartResize] = useState({ x: 0, y: 0, width: 0, height: 0, posX: 0, posY: 0 });

  const windowRef = useRef<HTMLDivElement>(null);

  // Mouse & Touch Move Handlers
  useEffect(() => {
    const handleMove = (clientX: number, clientY: number) => {
      if (isDragging && !windowState.isMaximized) {
        onMove(windowState.id, clientX - dragOffset.x, clientY - dragOffset.y);
      } else if (isResizing && resizeDir) {
        let newWidth = startResize.width;
        let newHeight = startResize.height;
        let newX = startResize.posX;
        let newY = startResize.posY;

        const deltaX = clientX - startResize.x;
        const deltaY = clientY - startResize.y;

        if (resizeDir.includes('e')) newWidth = startResize.width + deltaX;
        if (resizeDir.includes('w')) {
            newWidth = startResize.width - deltaX;
            newX = startResize.posX + deltaX;
        }
        if (resizeDir.includes('s')) newHeight = startResize.height + deltaY;
        if (resizeDir.includes('n')) {
            newHeight = startResize.height - deltaY;
            newY = startResize.posY + deltaY;
        }

        // Min Constraints
        if (newWidth < 300) newWidth = 300;
        if (newHeight < 200) newHeight = 200;

        onResize(windowState.id, newWidth, newHeight, newX, newY);
      }
    };

    const handleMouseMove = (e: MouseEvent) => {
        if (isDragging || isResizing) {
          e.preventDefault();
        }
        handleMove(e.clientX, e.clientY);
    };

    const handleTouchMove = (e: TouchEvent) => {
        if (isDragging || isResizing) {
            e.preventDefault(); // Prevent scrolling while dragging/resizing
        }
        if (e.touches.length > 0) {
            handleMove(e.touches[0].clientX, e.touches[0].clientY);
        }
    };

    const handleEnd = () => {
      setIsDragging(false);
      setIsResizing(false);
      setResizeDir(null);
    };

    if (isDragging || isResizing) {
      document.addEventListener('mousemove', handleMouseMove);
      document.addEventListener('mouseup', handleEnd);
      document.addEventListener('touchmove', handleTouchMove, { passive: false });
      document.addEventListener('touchend', handleEnd);
    }

    return () => {
      document.removeEventListener('mousemove', handleMouseMove);
      document.removeEventListener('mouseup', handleEnd);
      document.removeEventListener('touchmove', handleTouchMove);
      document.removeEventListener('touchend', handleEnd);
    };
  }, [isDragging, isResizing, dragOffset, startResize, resizeDir, onMove, onResize, windowState]);

  const handleStartDrag = (clientX: number, clientY: number) => {
    onFocus(windowState.id);
    setIsDragging(true);
    setDragOffset({
      x: clientX - windowState.position.x,
      y: clientY - windowState.position.y
    });
  };

  const handleMouseDown = (e: React.MouseEvent) => {
      // Only drag if left click
      if (e.button !== 0) return;
      handleStartDrag(e.clientX, e.clientY);
  };

  const handleTouchStart = (e: React.TouchEvent) => {
      // Prevent default to stop scrolling, but let click events fire for children if needed?
      // Actually for titlebar drag, we generally want to prevent scroll.
      // e.preventDefault(); 
      handleStartDrag(e.touches[0].clientX, e.touches[0].clientY);
  };

  const handleResizeStart = (e: React.MouseEvent | React.TouchEvent, dir: string) => {
      e.stopPropagation();
      // e.preventDefault(); 
      onFocus(windowState.id);
      setIsResizing(true);
      setResizeDir(dir);

      const clientX = 'touches' in e ? e.touches[0].clientX : (e as React.MouseEvent).clientX;
      const clientY = 'touches' in e ? e.touches[0].clientY : (e as React.MouseEvent).clientY;

      setStartResize({
          x: clientX,
          y: clientY,
          width: windowState.size.width,
          height: windowState.size.height,
          posX: windowState.position.x,
          posY: windowState.position.y
      });
  };

  if (!windowState.isOpen || windowState.isMinimized) return null;

  return (
    <div
      ref={windowRef}
      className={`absolute flex flex-col glass-panel window-shadow rounded-lg overflow-hidden transition-[opacity] duration-200 ${
        isDragging ? 'cursor-grabbing' : ''
      }`}
      style={{
        left: windowState.position.x,
        top: windowState.position.y,
        width: windowState.size.width,
        height: windowState.size.height,
        zIndex: windowState.zIndex,
        touchAction: 'none' // Important for touch devices
      }}
      onMouseDown={() => onFocus(windowState.id)}
      onTouchStart={() => onFocus(windowState.id)}
    >
      {/* Resize Handles (Invisible but larger for touch) */}
      {!windowState.isMaximized && (
        <>
            <div className="absolute top-0 left-0 w-full h-2 cursor-n-resize z-50 -mt-1" onMouseDown={(e) => handleResizeStart(e, 'n')} onTouchStart={(e) => handleResizeStart(e, 'n')} />
            <div className="absolute bottom-0 left-0 w-full h-2 cursor-s-resize z-50 -mb-1" onMouseDown={(e) => handleResizeStart(e, 's')} onTouchStart={(e) => handleResizeStart(e, 's')} />
            <div className="absolute top-0 left-0 h-full w-2 cursor-w-resize z-50 -ml-1" onMouseDown={(e) => handleResizeStart(e, 'w')} onTouchStart={(e) => handleResizeStart(e, 'w')} />
            <div className="absolute top-0 right-0 h-full w-2 cursor-e-resize z-50 -mr-1" onMouseDown={(e) => handleResizeStart(e, 'e')} onTouchStart={(e) => handleResizeStart(e, 'e')} />

            {/* Corners (Larger hit targets) */}
            <div className="absolute top-0 left-0 w-6 h-6 cursor-nw-resize z-50 -ml-2 -mt-2" onMouseDown={(e) => handleResizeStart(e, 'nw')} onTouchStart={(e) => handleResizeStart(e, 'nw')} />
            <div className="absolute top-0 right-0 w-6 h-6 cursor-ne-resize z-50 -mr-2 -mt-2" onMouseDown={(e) => handleResizeStart(e, 'ne')} onTouchStart={(e) => handleResizeStart(e, 'ne')} />
            <div className="absolute bottom-0 left-0 w-6 h-6 cursor-sw-resize z-50 -ml-2 -mb-2" onMouseDown={(e) => handleResizeStart(e, 'sw')} onTouchStart={(e) => handleResizeStart(e, 'sw')} />
            <div className="absolute bottom-0 right-0 w-6 h-6 cursor-se-resize z-50 -mr-2 -mb-2" onMouseDown={(e) => handleResizeStart(e, 'se')} onTouchStart={(e) => handleResizeStart(e, 'se')} />
        </>
      )}

      {/* Window Header (Aero Titlebar) */}
      <div
        className="h-8 flex items-center justify-between px-2 cursor-default select-none bg-gradient-to-b from-white/50 to-transparent border-b border-white/20 shrink-0 touch-none"
        onMouseDown={handleMouseDown}
        onTouchStart={handleTouchStart}
      >
        <div className="flex items-center gap-2 px-1 text-slate-800 shadow-black drop-shadow-sm pointer-events-none">
          <windowState.icon size={16} className="text-slate-900 opacity-80" />
          <span className="text-xs font-semibold tracking-wide text-slate-900/90" style={{ textShadow: '0 0 5px rgba(255,255,255,0.8)' }}>
            {windowState.title}
          </span>
        </div>

        <div 
          className="flex items-center window-controls gap-1"
          onMouseDown={(e) => { e.stopPropagation(); onFocus(windowState.id); }}
          onTouchStart={(e) => { e.stopPropagation(); onFocus(windowState.id); }}
        >
          <button
            onClick={(e) => { e.stopPropagation(); onMinimize(windowState.id); }}
            className="w-6 h-5 flex items-center justify-center hover:bg-white/40 rounded-sm border border-transparent hover:border-white/30 transition-colors"
          >
            <Minus size={12} className="text-slate-800" />
          </button>
          <button
            onClick={(e) => { e.stopPropagation(); onMaximize(windowState.id); }}
            className="w-6 h-5 flex items-center justify-center hover:bg-white/40 rounded-sm border border-transparent hover:border-white/30 transition-colors"
          >
             {windowState.isMaximized ? <Square size={10} className="text-slate-800" /> : <Maximize2 size={10} className="text-slate-800" />}
          </button>
          <button
            onClick={(e) => { e.stopPropagation(); onClose(windowState.id); }}
            className="w-10 h-5 flex items-center justify-center hover:bg-[#e81123] bg-transparent hover:text-white rounded-sm border border-transparent transition-colors group"
          >
            <X size={14} className="text-slate-800 group-hover:text-white" />
          </button>
        </div>
      </div>

      {/* Window Content */}
      <div className="flex-1 bg-white/80 overflow-hidden relative flex flex-col cursor-auto">
        {children}
      </div>
    </div>
  );
};

export enum AppId {
  ABOUT = 'ABOUT',
  PROJECTS = 'PROJECTS',
  CONTACT = 'CONTACT',
  CHAT = 'CHAT',
  GITHUB = 'GITHUB',
  AI_IMAGE_GEN = 'AI_IMAGE_GEN',
  NO_APP = 'NO_APP',
}

export interface WindowState {
  id: AppId;
  title: string;
  icon: any; // Lucide icon component
  isOpen: boolean;
  isMinimized: boolean;
  isMaximized: boolean;
  zIndex: number;
  position: { x: number; y: number };
  size: { width: number; height: number };
}

export enum ImageResolution {
  ONE_K = '1K',
  TWO_K = '2K',
  FOUR_K = '4K',
}

export interface ChatMessage {
