import React, { useState } from 'react';
import { ShieldAlert, AlertTriangle } from 'lucide-react';

export const NoApp: React.FC = () => {
  const [query, setQuery] = useState('');
  const [response, setResponse] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);

  const ask = async () => {
    if (!query.trim()) return;
    setLoading(true);
    setResponse(null);

    try {
      // Attempt to fetch from a common deployment of No as a Service.
      // If the external service is down, we fallback to a local simulation.
      const controller = new AbortController();
      const timeoutId = setTimeout(() => controller.abort(), 3000);

      const res = await fetch('https://no-api-server.vercel.app/', { 
          signal: controller.signal,
          headers: { 'Accept': 'text/plain' }
      });
      clearTimeout(timeoutId);

      if (res.ok) {
          let text = await res.text();
          // Clean up response if needed (sometimes returns quotes)
          text = text.replace(/^"|"$/g, '').trim();
          setResponse(text || "No");
      } else {
          throw new Error('API Error');
      }
    } catch (e) {
      // Fallback responses if API is unreachable
      const fallbackNos = ["No", "NO", "No.", "Nope", "Nah", "Nay", "Negative", "Absolutely not", "Denied"];
      setResponse(fallbackNos[Math.floor(Math.random() * fallbackNos.length)]);
    } finally {
      setLoading(false);
    }
  };

  const handleReset = () => {
      setResponse(null);
      setQuery('');
  };

  return (
    <div className="h-full w-full bg-[#f0f0f0] flex flex-col font-[Segoe UI,sans-serif] p-0 select-none">
       {/* Header mimics UAC (User Account Control) */}
       <div className={`h-16 w-full ${response ? 'bg-[#d64545]' : 'bg-[#e99f00]'} flex items-center px-4 gap-4 overflow-hidden relative transition-colors duration-500`}>
          {/* Gloss overlay */}
          <div className="absolute inset-0 bg-gradient-to-b from-white/30 to-transparent pointer-events-none"></div>

          <div className="z-10 bg-white rounded-full p-1.5 shadow-sm border border-black/10">
             {response ? (
                 <AlertTriangle size={24} className="text-[#d64545]" />
             ) : (
                 <ShieldAlert size={24} className="text-[#e99f00]" />
             )}
          </div>

          <div className="z-10 text-white drop-shadow-md">
             <div className="text-lg font-medium tracking-tight">
                 {response ? 'Permission Denied' : 'User Account Control'}
             </div>
             <div className="text-xs opacity-90">
                 {response ? 'The system administrator rejected your request.' : 'Do you want to allow this action?'}
             </div>
          </div>
       </div>

       <div className="flex-1 p-6 flex flex-col gap-4 bg-[#f0f0f0]">
          {!response ? (
            <div className="flex flex-col h-full animate-in slide-in-from-bottom-2 duration-300">
                <div className="text-sm text-slate-700 mb-4">
                    <span className="font-bold block mb-1 text-slate-800">Program name:</span> Life Decision Helper
                    <span className="font-bold block mt-2 mb-1 text-slate-800">Verified publisher:</span> No as a Service
                </div>

                <div className="flex flex-col gap-1 flex-1">
                    <label className="text-xs text-slate-500 uppercase font-semibold">Describe your request</label>
                    <textarea 
                        className="w-full flex-1 border border-[#8e98a1] p-3 text-sm focus:border-[#0066cc] outline-none resize-none font-sans shadow-inner bg-white rounded-sm"
                        placeholder="e.g. Can I deploy to production on a Friday?"
                        value={query}
                        onChange={(e) => setQuery(e.target.value)}
                        autoFocus
                    />
                </div>
            </div>
          ) : (
             <div className="flex-1 flex flex-col items-center justify-center text-center animate-in zoom-in-95 duration-300">
                 <div className="text-[100px] font-bold text-slate-800 leading-none mb-6 drop-shadow-sm tracking-tighter">
                    {response}
                 </div>
                 <div className="bg-white border border-[#d9d9d9] p-3 rounded shadow-sm max-w-[80%]">
                    <div className="text-[10px] text-slate-400 uppercase tracking-wider font-bold mb-1">Your Request</div>
                    <div className="text-slate-700 text-sm italic">"{query}"</div>
                 </div>
             </div>
          )}
       </div>

       {/* Footer Actions */}
       <div className="h-12 bg-[#f0f0f0] border-t border-[#dfdfdf] flex items-center justify-end px-4 gap-2 flex-shrink-0">
          {!response ? (
              <>
                <button 
                    onClick={ask}
                    disabled={loading || !query}
                    className="min-w-[80px] px-4 py-1 border border-[#3c7fb1] bg-gradient-to-b from-[#f2f2f2] to-[#cfcfcf] hover:from-[#e6e6e6] hover:to-[#b8b8b8] rounded-[2px] text-xs font-semibold text-slate-800 shadow-[inset_0_1px_0_white,0_1px_2px_rgba(0,0,0,0.1)] active:translate-y-px disabled:opacity-50 disabled:cursor-not-allowed transition-all"
                >
                    {loading ? 'Verifying...' : 'Yes'}
                </button>
                <button className="min-w-[80px] px-4 py-1 border border-[#adadad] bg-gradient-to-b from-[#f2f2f2] to-[#cfcfcf] hover:from-[#e6e6e6] hover:to-[#b8b8b8] rounded-[2px] text-xs font-semibold text-slate-800 shadow-[inset_0_1px_0_white,0_1px_2px_rgba(0,0,0,0.1)] active:translate-y-px transition-all">
                    No
                </button>
              </>
          ) : (
              <button 
                  onClick={handleReset}
                  className="min-w-[80px] px-4 py-1 border border-[#adadad] bg-gradient-to-b from-[#f2f2f2] to-[#cfcfcf] hover:from-[#e6e6e6] hover:to-[#b8b8b8] rounded-[2px] text-xs font-semibold text-slate-800 shadow-[inset_0_1px_0_white,0_1px_2px_rgba(0,0,0,0.1)] active:translate-y-px transition-all"
              >
                  Close
              </button>
          )}
       </div>
    </div>
  );
};

import React, { useState, useEffect, useCallback } from 'react';
