             {['Control Panel', 'Devices and Printers', 'Default Programs', 'Help and Support'].map(item => (
                 <button key={item} className="w-full text-left px-3 py-1.5 hover:bg-white/10 rounded-sm transition-colors hover:text-white">
                     {item}
