import React, { useState } from 'react';
import { AlertTriangle, XCircle, Check } from 'lucide-react';
import { soundService } from '../../services/soundService';

const FALLBACK_NOS = [
  "This feels like something Future Me would yell at Present Me for agreeing to.",
  "I'm currently booked for the next decade in pretending to be productive.",
  "Accepting that offer would cause a glitch in the Matrix.",
  "My future self wrote me a note: 'Please don't do this again.'",
  "I'd rather say no with honesty than yes with resentment.",
  "I have zero interest in doing that, but I support you doing it somewhere else.",
  "I’m going to have to go with a hard no on this one.",
  "My schedule is currently full of 'not doing that'."
];

export const NoApp: React.FC = () => {
  const [request, setRequest] = useState('');
  const [status, setStatus] = useState<'idle' | 'processing' | 'rejected'>('idle');
  const [rejectionReason, setRejectionReason] = useState('');
  const [progress, setProgress] = useState(0);

  const handleSubmit = async () => {
    if (!request.trim()) return;

    setStatus('processing');
    setProgress(0);

    // Simulate progress bar
    const interval = setInterval(() => {
      setProgress(prev => {
        if (prev >= 90) return prev;
        return prev + Math.random() * 10;
      });
    }, 100);

    try {
        // Attempt to fetch from No as a Service API
        // Using a controller to timeout if it takes too long
        const controller = new AbortController();
        const timeoutId = setTimeout(() => controller.abort(), 1200);

        // We fetch the message. Note: the URL in prompt is specific, we'll try to use it or fallback
        // Since CORS might be an issue with some public APIs in browser, we prepare to catch.
        const res = await fetch('https://no-api.netlify.app/api/v1/no', { 
            signal: controller.signal,
            headers: { 'Accept': 'application/json' }
        });
        clearTimeout(timeoutId);

        let reason = "";
        if (res.ok) {
            const data = await res.json();
            // The API usually returns { "no": "..." } or similar structure
            reason = data.message || data.no || data.quote || FALLBACK_NOS[Math.floor(Math.random() * FALLBACK_NOS.length)];
        } else {
            throw new Error('API failed');
        }

        // Ensure we have a string
        setRejectionReason(String(reason));

    } catch (e) {
        setRejectionReason(FALLBACK_NOS[Math.floor(Math.random() * FALLBACK_NOS.length)]);
    }

    // Wait for the "processing" visual to finish (1.5s total)
    setTimeout(() => {
        clearInterval(interval);
        setProgress(100);

        setTimeout(() => {
            setStatus('rejected');
            soundService.play('error');
        }, 200); 
    }, 1500);
  };

  const handleReset = () => {
    setStatus('idle');
    setRequest('');
    setRejectionReason('');
    setProgress(0);
  };

  return (
    <div className="h-full w-full bg-[#f0f0f0] flex flex-col font-[Segoe UI,sans-serif] p-4 select-none text-slate-800">

       {/* Header Section */}
       <div className="flex items-start gap-4 mb-6">
          <div className="mt-1">
             <AlertTriangle size={32} className="text-yellow-500 drop-shadow-sm" />
          </div>
          <div className="flex-1">
             <h2 className="text-[#003399] text-base font-normal mb-1">Submit a request to the Administrator</h2>
             <p className="text-xs text-slate-600 leading-relaxed">
                Use this form to request elevated privileges, budget approval, or feature changes. 
                High priority requests regarding "production deployments on Friday" may be processed with extreme prejudice.
             </p>
          </div>
       </div>

       {/* Form Section */}
       <div className="flex-1 flex flex-col gap-2">
          <label className="text-xs text-slate-700 font-semibold">Reason for Request:</label>
          <textarea 
            className="w-full h-24 border border-[#8e98a1] p-2 text-sm focus:border-[#0066cc] outline-none resize-none font-sans shadow-[inset_0_1px_2px_rgba(0,0,0,0.1)] bg-white rounded-sm disabled:bg-slate-100 disabled:text-slate-500"
            placeholder="e.g. I need admin access to install a new theme..."
            value={request}
            onChange={(e) => setRequest(e.target.value)}
            disabled={status !== 'idle'}
            autoFocus
          />
       </div>

       {/* Status / Output Section */}
       <div className="mt-4 mb-4 min-h-[80px] border border-[#d9d9d9] bg-white p-3 rounded-sm relative overflow-hidden">
          {status === 'idle' && (
              <div className="text-xs text-slate-400 italic text-center mt-4">
                  Ready to process request...
              </div>
          )}

          {status === 'processing' && (
              <div className="flex flex-col items-center justify-center h-full gap-2">
                  <div className="text-xs text-slate-600">Contacting System Administrator...</div>
                  <div className="w-full h-4 bg-[#e6e6e6] border border-[#bcbcbc] rounded-sm relative overflow-hidden p-[1px]">
                      <div 
                        className="h-full bg-gradient-to-b from-[#00d42a] to-[#00aa22] shadow-[inset_0_1px_0_rgba(255,255,255,0.4)] transition-all duration-100 ease-out"
                        style={{ width: `${progress}%` }}
                      ></div>
                      {/* Gloss effect on bar */}
                      <div className="absolute top-0 left-0 right-0 h-1/2 bg-white/20"></div>
                  </div>
              </div>
          )}

          {status === 'rejected' && (
              <div className="flex items-start gap-3 animate-in zoom-in-95 duration-200">
                  <XCircle size={24} className="text-red-600 flex-shrink-0 mt-0.5" />
                  <div className="flex flex-col gap-1">
                      <span className="text-xs font-bold text-red-700">Request Denied</span>
                      <p className="text-sm text-slate-800 leading-snug">
                          {rejectionReason}
                      </p>
                  </div>
              </div>
          )}
       </div>

       {/* Footer Buttons */}
       <div className="flex justify-end gap-2 pt-3 border-t border-[#dfdfdf]">
          {status === 'idle' ? (
              <button 
                onClick={handleSubmit}
                disabled={!request.trim()}
                className="min-w-[80px] px-3 py-1 border border-[#3c7fb1] bg-gradient-to-b from-[#f2f2f2] to-[#cfcfcf] hover:from-[#e6e6e6] hover:to-[#b8b8b8] rounded-[2px] text-xs font-semibold text-slate-800 shadow-[inset_0_1px_0_white,0_1px_2px_rgba(0,0,0,0.1)] active:translate-y-px disabled:opacity-50 disabled:cursor-not-allowed transition-all"
              >
                 Submit Request
              </button>
          ) : status === 'rejected' ? (
              <button 
                onClick={handleReset}
                className="min-w-[80px] px-3 py-1 border border-[#adadad] bg-gradient-to-b from-[#f2f2f2] to-[#cfcfcf] hover:from-[#e6e6e6] hover:to-[#b8b8b8] rounded-[2px] text-xs font-semibold text-slate-800 shadow-[inset_0_1px_0_white,0_1px_2px_rgba(0,0,0,0.1)] active:translate-y-px transition-all"
              >
                 Close
              </button>
          ) : (
              <button 
                disabled
                className="min-w-[80px] px-3 py-1 border border-[#adadad] bg-slate-100 text-slate-400 rounded-[2px] text-xs font-semibold cursor-wait"
              >
                 Processing...
              </button>
          )}
       </div>
    </div>
  );
};

import React, { useState, useEffect, useCallback } from 'react';
import { Taskbar } from './components/ui/Taskbar';
import { StartMenu } from './components/ui/StartMenu';
import { Window } from './components/ui/Window';
import { LiveBackground } from './components/ui/LiveBackground';
import { LoginScreen } from './components/ui/LoginScreen';
import { ContextMenu } from './components/ui/ContextMenu';
import { AboutApp } from './components/apps/AboutApp';
import { ProjectsApp } from './components/apps/ProjectsApp';
import { ChatApp } from './components/apps/ChatApp';
import { ContactApp } from './components/apps/ContactApp';
import { NoApp } from './components/apps/NoApp';
import { AppId, WindowState } from './types';
import { User, Briefcase, Mail, MessageSquare, Github, ShieldAlert } from 'lucide-react';
import { soundService } from './services/soundService';

const INITIAL_WINDOWS: WindowState[] = [
  {
    id: AppId.ABOUT,
    title: 'About Me',
    icon: User,
    isOpen: true,
    isMinimized: false,
    isMaximized: false,
    zIndex: 1,
    position: { x: 50, y: 50 },
    size: { width: 600, height: 450 },
  },
  {
    id: AppId.PROJECTS,
    title: 'My Projects',
    icon: Briefcase,
    isOpen: false,
    isMinimized: false,
    isMaximized: false,
    zIndex: 2,
    position: { x: 100, y: 80 },
    size: { width: 750, height: 500 },
  },
  {
    id: AppId.CHAT,
    title: 'Keshav AI Chat',
    icon: MessageSquare,
    isOpen: false,
    isMinimized: false,
    isMaximized: false,
    zIndex: 3,
    position: { x: 150, y: 110 },
    size: { width: 500, height: 600 },
  },
  {
    id: AppId.CONTACT,
    title: 'Contact',
    icon: Mail,
    isOpen: false,
    isMinimized: false,
    isMaximized: false,
    zIndex: 4,
    position: { x: 200, y: 140 },
    size: { width: 650, height: 450 },
  },
  {
    id: AppId.NO_APP,
    title: 'System Administrator Request Tool',
    icon: ShieldAlert,
    isOpen: false,
    isMinimized: false,
    isMaximized: false,
    zIndex: 5,
    position: { x: 250, y: 170 },
    size: { width: 450, height: 380 },
  },
];

const App: React.FC = () => {
  const [isLoggedIn, setIsLoggedIn] = useState(false);
  const [windows, setWindows] = useState<WindowState[]>(INITIAL_WINDOWS);
  const [activeWindowId, setActiveWindowId] = useState<AppId | null>(AppId.ABOUT);
  const [isStartOpen, setIsStartOpen] = useState(false);
  const [maxZIndex, setMaxZIndex] = useState(5);

  // New States
  const [contextMenu, setContextMenu] = useState<{ visible: boolean; x: number; y: number } | null>(null);
  const [isShuttingDown, setIsShuttingDown] = useState(false);
  const [bsod, setBsod] = useState(false);
  const [keySequence, setKeySequence] = useState<string[]>([]);

  // BSOD Easter Egg Listener
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      const key = e.key.toLowerCase();
      setKeySequence(prev => {
        const newSeq = [...prev, key].slice(-4);
        if (newSeq.join('') === 'bsod') {
          setBsod(true);
        }
        return newSeq;
      });
    };
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, []);

  const handleLogin = () => {
    soundService.play('startup');
    setIsLoggedIn(true);
  };

  const handleFocus = (id: AppId) => {
    setActiveWindowId(id);
    setWindows(prev => prev.map(w => 
      w.id === id ? { ...w, zIndex: maxZIndex + 1, isMinimized: false } : w
    ));
    setMaxZIndex(z => z + 1);
  };

  const handleOpenApp = (id: AppId) => {
    if (id === AppId.GITHUB) {
        soundService.play('click');
        window.open('https://github.com/Keshav-gehlot', '_blank');
        return;
    }

    const target = windows.find(w => w.id === id);
    if (!target) return;

    if (target.isOpen) {
        handleFocus(id);
    } else {
        soundService.play('open');
        setWindows(prev => prev.map(w => 
            w.id === id ? { ...w, isOpen: true, zIndex: maxZIndex + 1, isMinimized: false } : w
        ));
        setMaxZIndex(z => z + 1);
        setActiveWindowId(id);
    }
  };

  const handleClose = (id: AppId) => {
    soundService.play('close');
    setWindows(prev => prev.map(w => w.id === id ? { ...w, isOpen: false, isMinimized: false } : w));
    if (activeWindowId === id) setActiveWindowId(null);
  };

  const handleMinimize = (id: AppId) => {
    soundService.play('minimize');
    setWindows(prev => prev.map(w => w.id === id ? { ...w, isMinimized: true } : w));
    if (activeWindowId === id) setActiveWindowId(null);
  };

  const handleMaximize = (id: AppId) => {
     setWindows(prev => prev.map(w => {
         if (w.id !== id) return w;
         if (w.isMaximized) {
             soundService.play('minimize');
             return { 
                ...w, 
                isMaximized: false, 
                position: { x: 50 + (Math.random() * 50), y: 50 + (Math.random() * 50) }, 
                size: w.id === AppId.PROJECTS ? { width: 750, height: 500 } : { width: 600, height: 450 } 
             };
         } else {
             soundService.play('open');
             return { ...w, isMaximized: true, position: { x: 0, y: 0 }, size: { width: window.innerWidth, height: window.innerHeight - 40 } };
         }
     }));
     handleFocus(id);
  };

  const handleMove = (id: AppId, x: number, y: number) => {
    setWindows(prev => prev.map(w => 
      w.id === id && !w.isMaximized ? { ...w, position: { x, y } } : w
    ));
  };

  const handleResize = (id: AppId, width: number, height: number, x: number, y: number) => {
      setWindows(prev => prev.map(w => 
          w.id === id ? { ...w, size: { width, height }, position: { x, y } } : w
      ));
  };

  const handleTaskbarClick = (id: AppId) => {
      const w = windows.find(win => win.id === id);
      soundService.play('click');
      if (w?.isMinimized || activeWindowId !== id) {
          handleFocus(id);
      } else {
          handleMinimize(id);
      }
      setIsStartOpen(false);
  };

  const handleShowDesktop = () => {
    const anyOpen = windows.some(w => w.isOpen && !w.isMinimized);
    if (anyOpen) {
        soundService.play('minimize');
        setWindows(prev => prev.map(w => ({ ...w, isMinimized: true })));
        setActiveWindowId(null);
    } else {
        // Restore logic could be implemented here to toggle back
    }
  };

  const handleContextMenu = (e: React.MouseEvent) => {
    e.preventDefault();
    setContextMenu({ visible: true, x: e.clientX, y: e.clientY });
  };

  const handleShutdown = () => {
    setIsShuttingDown(true);
    // Transition to login screen after delay instead of reload
    setTimeout(() => {
        setIsShuttingDown(false);
        setIsLoggedIn(false);
        // Reset state
        setWindows(INITIAL_WINDOWS);
        setActiveWindowId(AppId.ABOUT);
        setIsStartOpen(false);
    }, 4000);
  };

  // Extra Desktop Icons mapping
  const desktopIcons = [
      { id: AppId.ABOUT, label: 'About Me', icon: User },
      { id: AppId.PROJECTS, label: 'Projects', icon: Briefcase },
      { id: AppId.CHAT, label: 'Chat', icon: MessageSquare },
      { id: AppId.NO_APP, label: 'Permissions', icon: ShieldAlert },
      { id: AppId.CONTACT, label: 'Contact Me', icon: Mail },
      { id: AppId.GITHUB, label: 'GitHub', icon: Github },
  ];

  if (bsod) {
      return (
          <div className="fixed inset-0 bg-[#000082] text-white font-[ 'Lucida Console', monospace] p-8 z-[99999] cursor-none" onClick={() => setBsod(false)}>
              <div className="max-w-4xl">
                <p className="mb-8">A problem has been detected and Windows has been shut down to prevent damage to your computer.</p>
                <p className="mb-8">DRIVER_IRQL_NOT_LESS_OR_EQUAL</p>
                <p className="mb-8">If this is the first time you've seen this Stop error screen, restart your computer. If this screen appears again, follow these steps:</p>
                <p className="mb-8">Check to make sure any new hardware or software is properly installed. If this is a new installation, ask your hardware or software manufacturer for any Windows updates you might need.</p>
                <p className="mb-8">Technical information:</p>
                <p className="mb-8">*** STOP: 0x000000D1 (0x0000000C, 0x00000002, 0x00000000, 0xF86B5A89)</p>
                <p className="mb-8">***  gv3.sys - Address F86B5A89 base at F86B5000, DateStamp 3dd9919eb</p>
                <p>Beginning dump of physical memory</p>
                <p>Physical memory dump complete.</p>
                <p>Contact your system administrator or technical support group for further assistance.</p>
              </div>
          </div>
      );
  }

  if (isShuttingDown) {
      return (
          <div className="fixed inset-0 z-[9999] cursor-wait select-none font-[Segoe UI,sans-serif] overflow-hidden">
               {/* Background with blur to mimic Windows 7 overlay */}
               <div className="absolute inset-0 bg-black"></div>
               <div 
                  className="absolute inset-0 bg-cover bg-center opacity-40 blur-sm"
                  style={{ backgroundImage: 'url("https://images.unsplash.com/photo-1614850523459-c2f4c699c52e?ixlib=rb-4.0.3&auto=format&fit=crop&w=1920&q=80")' }}
               ></div>

               <div className="relative z-10 h-full w-full flex flex-col items-center justify-center animate-in fade-in duration-1000">
                   <div className="flex flex-col items-center gap-6">
                       <div className="w-12 h-12 rounded-full border-4 border-white/20 border-t-white/90 border-r-white/90 animate-spin shadow-[0_0_15px_rgba(255,255,255,0.3)]"></div>
                       <div className="text-center space-y-1">
                            <h2 className="text-white text-2xl font-light tracking-wide drop-shadow-lg">Shutting down...</h2>
                            <p className="text-blue-100/80 text-base font-light tracking-wide mt-2">Thank you for visiting.</p>
                       </div>
                   </div>
               </div>
          </div>
      );
  }

  if (!isLoggedIn) {
      return <LoginScreen onLogin={handleLogin} />;
  }

  return (
    <div 
      className="h-screen w-screen overflow-hidden relative select-none animate-in fade-in duration-700"
      onClick={() => {
          setIsStartOpen(false);
          setContextMenu(null);
      }}
      onContextMenu={handleContextMenu}
    >
      {/* Background Layer - Static Wallpaper */}
      <div 
        className="absolute inset-0 z-[-2]"
        style={{
            background: 'url("https://images.unsplash.com/photo-1614850523459-c2f4c699c52e?ixlib=rb-4.0.3&auto=format&fit=crop&w=1920&q=80") center/cover no-repeat'
        }}
      />

      {/* Interactive Layer - Particles */}
      <LiveBackground />

      {/* Desktop Icons */}
      <div className="absolute top-4 left-4 flex flex-col gap-6 items-start z-0">
        {desktopIcons.map(icon => (
            <button 
                key={icon.id}
                onDoubleClick={(e) => { e.stopPropagation(); handleOpenApp(icon.id); }}
                className="flex flex-col items-center gap-1 w-[80px] group text-center cursor-default hover:bg-white/10 rounded border border-transparent hover:border-white/20 p-2 transition-colors focus:bg-white/20 focus:border-white/30 active:bg-white/20"
                onClick={(e) => { e.stopPropagation(); soundService.play('click'); }}
            >
                <div className="drop-shadow-2xl filter shadow-black transition-transform group-hover:scale-105 group-active:scale-95">
                    <icon.icon size={42} className="text-white drop-shadow-[0_2px_4px_rgba(0,0,0,0.6)]" strokeWidth={1.5} />
                </div>
                <span className="text-white text-xs drop-shadow-[0_1px_2px_rgba(0,0,0,1)] font-medium leading-tight line-clamp-2 shadow-black text-shadow-sm" style={{ textShadow: '0 0 4px rgba(0,0,0,0.8)' }}>
                    {icon.label}
                </span>
            </button>
        ))}
      </div>

      {/* Windows Layer */}
      {windows.map(window => (
        <Window
          key={window.id}
          windowState={window}
          onClose={handleClose}
          onMinimize={handleMinimize}
          onMaximize={handleMaximize}
          onFocus={handleFocus}
          onMove={handleMove}
          onResize={handleResize}
        >
          {window.id === AppId.ABOUT && <AboutApp />}
          {window.id === AppId.PROJECTS && <ProjectsApp />}
          {window.id === AppId.CHAT && <ChatApp />}
          {window.id === AppId.CONTACT && <ContactApp />}
          {window.id === AppId.NO_APP && <NoApp />}
        </Window>
      ))}

      {/* Context Menu */}
      {contextMenu && (
          <ContextMenu 
            x={contextMenu.x} 
            y={contextMenu.y} 
            onClose={() => setContextMenu(null)}
            onRefresh={() => {
                // Flash effect for refresh
                const bg = document.createElement('div');
                bg.className = "absolute inset-0 bg-white/20 z-50 pointer-events-none";
                document.body.appendChild(bg);
                setTimeout(() => document.body.removeChild(bg), 50);
            }} 
          />
      )}

      {/* System UI */}
      <StartMenu 
        isOpen={isStartOpen} 
        onOpenApp={handleOpenApp} 
        onClose={() => setIsStartOpen(false)} 
        onShutdown={handleShutdown}
      />

      <Taskbar 
        windows={windows} 
        activeWindowId={activeWindowId} 
        onAppClick={handleTaskbarClick} 
        onStartClick={() => { soundService.play('click'); setIsStartOpen(!isStartOpen); }}
        isStartOpen={isStartOpen}
        onShowDesktop={handleShowDesktop}
      />
    </div>
  );
};

export default App;

import React from 'react';
import { User, Power, Search, ChevronRight, FileText, Folder, MessageSquare, Mail, Github, Lock, ShieldAlert } from 'lucide-react';
import { AppId } from '../../types';
import { soundService } from '../../services/soundService';

interface StartMenuProps {
  isOpen: boolean;
  onOpenApp: (id: AppId) => void;
  onClose: () => void;
  onShutdown: () => void;
}

export const StartMenu: React.FC<StartMenuProps> = ({ isOpen, onOpenApp, onClose, onShutdown }) => {
  if (!isOpen) return null;

  const menuItems = [
    { id: AppId.ABOUT, label: 'About Me', icon: FileText, sub: 'Portfolio' },
    { id: AppId.PROJECTS, label: 'Projects', icon: Folder, sub: 'Explorer' },
    { id: AppId.CHAT, label: 'Chat', icon: MessageSquare, sub: 'AI Chat' },
    { id: AppId.NO_APP, label: 'Admin Request', icon: ShieldAlert, sub: 'Admin Control' },
